var usedH = 0;
var toolbar = card.querySelector(".lane-tv-toolbar");
var hintBar = card.querySelector(".lane-tv-hint-bar");
if (toolbar instanceof HTMLElement) usedH += toolbar.offsetHeight;
if (hintBar instanceof HTMLElement) usedH += hintBar.offsetHeight;

new_string:
var usedH = 0;
var grid = card.querySelector(".lane-tv-grid");
if (grid instanceof HTMLElement) {
    var panels = grid.querySelectorAll(".lane-tv-panel:not(.lane-tv-panel--ring)");
    for (var pi = 0; pi < panels.length; pi++) {
        var p = panels[pi];
        if (!(p instanceof HTMLElement)) continue;
        var bottom = p.offsetTop + p.offsetHeight;
        if (bottom > usedH) usedH = bottom;
    }
}
